package com.samlong.model;
import javax.persistence.*;import javax.validation.constraints.*;import java.time.LocalDateTime;
@Entity @Table(name="news_articles") public class NewsArticle {
 @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @NotBlank(message="新闻标题不能为空") @Size(max=255,message="新闻标题不能超过255个字符") @Column(nullable=false) private String title; @Size(max=50000,message="新闻正文不能超过50000个字符") @Column(columnDefinition="text") private String content; @Size(max=500) @Pattern(regexp="^$|^https?://.+|^/(uploads|images)/.+",message="封面图片地址格式不正确") private String imageUrl; @Size(max=64,message="新闻分类不能超过64个字符") private String category; @NotBlank(message="新闻状态不能为空") @Pattern(regexp="ACTIVE|DRAFT",message="新闻状态只能是发布或草稿") private String status="DRAFT"; @NotNull(message="发布时间不能为空") @PastOrPresent(message="发布时间不能晚于当前时间") private LocalDateTime publishedAt;
 public Long getId(){return id;}public void setId(Long v){id=v;}public String getTitle(){return title;}public void setTitle(String v){title=v;}public String getContent(){return content;}public void setContent(String v){content=v;}public String getImageUrl(){return imageUrl;}public void setImageUrl(String v){imageUrl=v;}public String getCategory(){return category;}public void setCategory(String v){category=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public LocalDateTime getPublishedAt(){return publishedAt;}public void setPublishedAt(LocalDateTime v){publishedAt=v;}
}
